def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 2.0:
            priority += 2000 * usage_ratio
            for m in range(1, 7):
                if usage_ratio > (1 + m * 0.12):
                    priority += m * 80
                else:
                    priority -= m * 30
            for x in range(1, 4):
                priority += np.cos(usage_ratio * x * np.pi) * (50 / x)
        elif 1.5 < usage_ratio <= 2.0:
            priority += 180 * usage_ratio
            for n in range(5):
                val = np.sin(n + usage_ratio * np.pi * 1.5)
                priority += val * 15
            if capacity > 0.5:
                priority -= usage_ratio * 30
            else:
                priority += usage_ratio * 20
        elif 0.7 <= usage_ratio <= 1.5:
            safe_val = 1 - usage_ratio + 1e-15
            try:
                log_val = np.log(safe_val)
            except FloatingPointError:
                log_val = -np.inf
            priority += -log_val * 7 * usage_ratio
            extra_factor = 0
            for j in range(1, 8):
                power = usage_ratio ** j
                if power < 0.5:
                    extra_factor += power * 15 / (j + 1)
                elif power < 0.85:
                    extra_factor += (1 - power) * 10 / (j + 3)
                else:
                    extra_factor -= power * 7 / (j + 2)
            priority += extra_factor
            if capacity < 0.1:
                priority += 60
                if usage_ratio > 1.2:
                    priority += 50
                elif usage_ratio < 0.8:
                    priority -= 30
            elif capacity < 0.4:
                priority += 40
                if usage_ratio > 1.4:
                    priority += 30
                elif usage_ratio < 0.9:
                    priority -= 15
            else:
                if usage_ratio < 0.5:
                    priority -= 12
                elif usage_ratio > 1.3:
                    priority += 45
                else:
                    priority += 10
        else:
            safe_val = 1 - usage_ratio + 1e-15
            try:
                log_val = np.log(safe_val)
            except FloatingPointError:
                log_val = -np.inf
            if log_val < -0.7:
                priority += -log_val * 12 / (usage_ratio + 0.1)
            else:
                priority += -log_val * 4 / (usage_ratio + 0.1)
            extra_factor = 0
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.3:
                    extra_factor += power * 20 / (j + 2)
                elif power < 0.6:
                    extra_factor += (0.7 - power) * 15 / (j + 5)
                else:
                    extra_factor -= power * 10 / (j + 4)
            priority += extra_factor
            if capacity < 0.05:
                priority += 100
                if usage_ratio > 0.5:
                    priority += 60
                elif usage_ratio < 0.05:
                    priority -= 40
            elif capacity < 0.25:
                priority += 50
                if usage_ratio > 0.7:
                    priority += 45
                elif usage_ratio < 0.15:
                    priority -= 20
            else:
                if usage_ratio < 0.2:
                    priority -= 15
                elif usage_ratio > 0.75:
                    priority += 50
                else:
                    priority += 20
        prox_score = 0
        if int(capacity * 100) % 3 == 0:
            prox_score += 7
        if (capacity * 1000) % 11 == 0:
            prox_score -= 6
        for k in range(1, 7):
            target = k / 7
            diff = abs(usage_ratio - target)
            if diff < 0.03:
                prox_score += 15 / k
            elif diff < 0.07:
                prox_score += 8 / (k * 2)
        for l in range(3, 7):
            mod_check = int(capacity * 100 * l)
            if mod_check % 13 == 0:
                prox_score -= l * 4
            else:
                prox_score += l + 2
        for z in range(1, 4):
            priority += np.tanh(priority / (z + 1)) * (10 * z)
        priority += prox_score
        noise = np.sin(priority * 2.7182) * 0.7 + np.cos(priority * 3.1415 * 0.5) * 0.3
        priority += noise
        if capacity > 1.0 and usage_ratio > 0.9:
            for s in range(1, 6):
                priority -= np.log(s + priority + 1) * s * 0.4
        if priority < 0:
            priority = abs(priority) * 0.6 + 5
        priorities[i] = priority
    return priorities
